/* ─────────────────────────────────────────────────────────────────────────────
   Coach Login
────────────────────────────────────────────────────────────────────────────── */
function CoachLogin({ onLoggedIn }) {
  const [email, setEmail] = useState("");
  const [pass, setPass] = useState("");
  const [err, setErr] = useState("");
  const [loading, setLoading] = useState(false);
  const [showPass, setShowPass] = useState(false);

  const handleLogin = async () => {
    setErr("");
    if (!email.trim() || !pass) {
      setErr("Enter your coach credentials.");
      return;
    }
    setLoading(true);
    try {
      const data = await apiFetch("/auth/login", null, {
        method: "POST",
        body: JSON.stringify({ email: email.trim().toLowerCase(), password: pass }),
      });

      // data: { token, user }  (your backend returns this) [1](https://github.com/orgs/community/discussions/151670)
      localStorage.setItem(TOKEN_KEY, data.token);
      onLoggedIn({ ...data.user, token: data.token });
    } catch (e) {
      setErr(e.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div
      style={{
        minHeight: "100vh",
        background: T.bg,
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        padding: 24,
        fontFamily: "DM Sans",
      }}
    >
      <style>{`
        *{box-sizing:border-box;margin:0;padding:0}
        input::placeholder{color:${T.muted}}
        input{caret-color:${T.accent}}
        @keyframes fadeUp{from{opacity:0;transform:translateY(16px)}to{opacity:1;transform:translateY(0)}}
      `}</style>

      <div style={{ width: "100%", maxWidth: 440, animation: "fadeUp .35s ease" }}>
        <div style={{ textAlign: "center", marginBottom: 34 }}>
          <div style={{ display: "flex", justifyContent: "center", marginBottom: 10 }}>
            <img
              src={LOGO_SRC}
              alt="No Rules Nutrition"
              style={{
                width: 120,
                height: 120,
                borderRadius: "50%",
                objectFit: "cover",
                border: `3px solid ${T.accent}44`,
                boxShadow: `0 0 32px ${T.accent}22`,
              }}
            />
          </div>

          <div
            style={{
              display: "inline-flex",
              alignItems: "center",
              gap: 8,
              background: `${T.coachGreen}18`,
              border: `1px solid ${T.coachGreen}44`,
              borderRadius: 999,
              padding: "4px 14px",
            }}
          >
            <div style={{ width: 6, height: 6, borderRadius: "50%", background: T.coachGreen }} />
            <span style={{ fontSize: 11, color: T.coachGreen, letterSpacing: 1.5, textTransform: "uppercase" }}>
              Coach Portal
            </span>
          </div>
        </div>

        <div style={{ background: T.card, border: `1px solid ${T.border}`, borderRadius: 20, padding: 30 }}>
          <div style={{ fontFamily: "Bebas Neue, system-ui", fontSize: 22, letterSpacing: 2, color: T.text, marginBottom: 22 }}>
            COACH SIGN IN
          </div>

          <div style={{ marginBottom: 14 }}>
            <label style={labelStyle}>Email</label>
            <input
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && handleLogin()}
              placeholder="coach@norules.com"
              type="email"
              style={inputStyle}
            />
          </div>

          <div style={{ marginBottom: 18 }}>
            <label style={labelStyle}>Password</label>
            <div style={{ position: "relative" }}>
              <input
                value={pass}
                onChange={(e) => setPass(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && handleLogin()}
                placeholder="••••••••"
                type={showPass ? "text" : "password"}
                style={{ ...inputStyle, paddingRight: 52 }}
              />
              <button
                onClick={() => setShowPass((p) => !p)}
                style={{
                  position: "absolute",
                  right: 10,
                  top: "50%",
                  transform: "translateY(-50%)",
                  background: "none",
                  border: "none",
                  color: T.muted,
                  cursor: "pointer",
                  fontSize: 12,
                  fontFamily: "DM Sans",
                }}
                type="button"
              >
                {showPass ? "hide" : "show"}
              </button>
            </div>
          </div>

          {err && (
            <div
              style={{
                background: `${T.danger}18`,
                border: `1px solid ${T.danger}44`,
                borderRadius: 10,
                padding: "10px 14px",
                marginBottom: 14,
                fontSize: 12,
                color: T.danger,
              }}
            >
              {err}
            </div>
          )}

          <button
            onClick={handleLogin}
            disabled={loading}
            style={{
              width: "100%",
              background: loading ? T.border : T.accent,
              color: loading ? T.muted : T.bg,
              border: "none",
              borderRadius: 12,
              padding: 14,
              fontFamily: "Bebas Neue, system-ui",
              fontSize: 18,
              letterSpacing: 2,
              cursor: loading ? "default" : "pointer",
              transition: "all .2s",
            }}
            type="button"
          >
            {loading ? "SIGNING IN…" : "ACCESS COACH PORTAL"}
          </button>
        </div>

      </div>
    </div>
  );
}

/* ─────────────────────────────────────────────────────────────────────────────
   Add Athlete Modal (persists to backend via POST /athletes)
────────────────────────────────────────────────────────────────────────────── */
function AddAthleteModal({ onClose, onCreate, creating }) {
  const SPORTS = ["Triathlon", "Powerlifting", "CrossFit", "Swimming", "Running", "Other"];

  const [form, setForm] = useState({
    name: "",
    loginEmail: "",
    password: "",
    sport: "Running",
    mfpUsername: "",
  });

  const set = (k) => (e) => setForm((p) => ({ ...p, [k]: e.target.value }));

  const valid =
    form.name.trim() &&
    form.loginEmail.trim() &&
    form.password.trim() &&
    form.password.trim().length >= 6;

  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        background: "#000000d0",
        zIndex: 999,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        padding: 20,
      }}
      onClick={(e) => e.target === e.currentTarget && onClose()}
    >
      <div
        style={{
          width: "100%",
          maxWidth: 560,
          background: T.card,
          border: `1px solid ${T.accent}44`,
          borderRadius: 22,
          overflow: "hidden",
          animation: "fadeUp .2s ease",
        }}
      >
        <div style={{ padding: "20px 24px", borderBottom: `1px solid ${T.border}`, display: "flex", justifyContent: "space-between" }}>
          <div>
            <div style={{ fontFamily: "Bebas Neue, system-ui", fontSize: 22, letterSpacing: 2, color: T.text }}>
              ADD NEW ATHLETE
            </div>
            <div style={{ fontFamily: "DM Sans", fontSize: 11, color: T.muted, marginTop: 4 }}>
              Creates an athlete account in the database (coach‑owned).
            </div>
          </div>
          <button
            onClick={onClose}
            style={{ background: "none", border: "none", color: T.muted, cursor: "pointer", fontSize: 20 }}
            type="button"
          >
            ✕
          </button>
        </div>

        <div style={{ padding: "18px 24px" }}>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
            <div>
              <label style={labelStyle}>Full Name *</label>
              <input value={form.name} onChange={set("name")} placeholder="e.g. Alex Morgan" style={inputStyle} />
            </div>

            <div>
              <label style={labelStyle}>Sport</label>
              <select
                value={form.sport}
                onChange={set("sport")}
                style={{ ...inputStyle, cursor: "pointer" }}
              >
                {SPORTS.map((s) => (
                  <option key={s} value={s} style={{ background: T.bg }}>
                    {s}
                  </option>
                ))}
              </select>
            </div>
          </div>

          <div style={{ marginTop: 12 }}>
            <label style={labelStyle}>Portal Login Email *</label>
            <input value={form.loginEmail} onChange={set("loginEmail")} placeholder="athlete@norules.com" style={inputStyle} />
          </div>

          <div style={{ marginTop: 12 }}>
            <label style={labelStyle}>Password * (min 6 chars)</label>
            <input value={form.password} onChange={set("password")} placeholder="Create a password…" style={inputStyle} />
            {form.password && form.password.length < 6 && (
              <div style={{ marginTop: 6, fontFamily: "DM Sans", fontSize: 11, color: T.danger }}>
                Password must be at least 6 characters.
              </div>
            )}
          </div>

          <div style={{ marginTop: 12 }}>
            <label style={labelStyle}>MyFitnessPal Username (optional)</label>
            <input value={form.mfpUsername} onChange={set("mfpUsername")} placeholder="e.g. alexmorgan" style={inputStyle} />
          </div>

          <div style={{ display: "flex", gap: 10, marginTop: 18 }}>
            <button
              onClick={onClose}
              style={{
                flex: 1,
                background: "none",
                border: `1px solid ${T.border}`,
                borderRadius: 10,
                padding: 11,
                color: T.muted,
                fontFamily: "DM Sans",
                fontSize: 13,
                cursor: "pointer",
              }}
              type="button"
            >
              Cancel
            </button>

            <button
              onClick={() => onCreate(form)}
              disabled={!valid || creating}
              style={{
                flex: 2,
                background: valid ? T.accent : T.border,
                color: valid ? T.bg : T.muted,
                border: "none",
                borderRadius: 10,
                padding: 11,
                fontFamily: "Bebas Neue, system-ui",
                fontSize: 16,
                letterSpacing: 1.5,
                cursor: valid && !creating ? "pointer" : "default",
                transition: "all .2s",
              }}
              type="button"
            >
              {creating ? "CREATING…" : "CREATE ATHLETE"}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

/* ─────────────────────────────────────────────────────────────────────────────
   Weekly Macro Plan — Rows per day
   - GET /macro-plans/:athleteId (optional but recommended)
   - PUT /macro-plans/:athleteId
────────────────────────────────────────────────────────────────────────────── */
function WeeklyMacroPlan({ athleteId, baseTargets, token, onSaved }) {
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [err, setErr] = useState("");
  const [saved, setSaved] = useState(false);

  const emptyWeek = () =>
    DAYS.reduce((acc, d) => {
      acc[d] = {
        calories: baseTargets?.calories ?? 2000,
        protein: baseTargets?.protein ?? 150,
        carbs: baseTargets?.carbs ?? 200,
        fat: baseTargets?.fat ?? 70,
      };
      return acc;
    }, {});

  const [plan, setPlan] = useState(emptyWeek());

  useEffect(() => {
    // refresh defaults when athlete changes
    setPlan(emptyWeek());
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [athleteId]);

  // Load weekly macro plan from backend
  useEffect(() => {
    let ignore = false;
    (async () => {
      if (!athleteId || !token) return;
      setLoading(true);
      setErr("");
      try {
        const rows = await apiFetch(`/macro-plans/${athleteId}`, token);
        if (ignore) return;
        const byDay = {};
        (Array.isArray(rows) ? rows : []).forEach((r) => {
          const d = r.day_of_week;
          if (!d) return;
          byDay[d] = {
            calories: Number(r.calories || 0),
            protein: Number(r.protein_g || 0),
            carbs: Number(r.carbs_g || 0),
            fat: Number(r.fat_g || 0),
          };
        });
        setPlan((prev) => {
          const next = { ...prev };
          DAYS.forEach((d) => {
            if (byDay[d]) next[d] = { ...next[d], ...byDay[d] };
          });
          return next;
        });
      } catch (e) {
        if (!ignore) setErr(e.message || "Could not load macro plan");
      } finally {
        if (!ignore) setLoading(false);
      }
    })();
    return () => {
      ignore = true;
    };
  }, [athleteId, token]);

  const setCell = (day, key, value) => {
    const n = Math.max(0, Math.min(20000, Number(value) || 0));
    setPlan((prev) => ({
      ...prev,
      [day]: { ...prev[day], [key]: n },
    }));
  };

  const save = async () => {
    if (!athleteId) return;
    setSaving(true);
    setErr("");
    try {
      const plans = DAYS.map((d) => ({
        dayOfWeek: d,
        calories: Number(plan[d]?.calories || 0),
        protein_g: Number(plan[d]?.protein || 0),
        carbs_g: Number(plan[d]?.carbs || 0),
        fat_g: Number(plan[d]?.fat || 0),
      }));
      await apiFetch(`/macro-plans/${athleteId}`, token, {
        method: "PUT",
        body: JSON.stringify({ plans }),
      });
      setSaved(true);
      setTimeout(() => setSaved(false), 1500);
      onSaved?.();
    } catch (e) {
      setErr(e.message || "Could not save macro plan");
    } finally {
      setSaving(false);
    }
  };

  return (
    <div style={{ background: T.card, border: `1px solid ${T.border}`, borderRadius: 16, padding: 16 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", gap: 10, flexWrap: "wrap" }}>
        <div>
          <div style={{ fontFamily: "Bebas Neue, system-ui", fontSize: 18, letterSpacing: 2, color: T.text }}>MACRO PLAN</div>
          <div style={{ fontFamily: "DM Sans", fontSize: 12, color: T.muted }}>Set targets per day (saved to backend)</div>
        </div>
        <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
          <button onClick={save} disabled={saving || loading} style={{ ...miniBtnStyle(), borderColor: `${T.accent}55`, color: T.accent }} type="button">
            {saving ? "SAVING…" : loading ? "LOADING…" : "SAVE"}
          </button>
        </div>
      </div>

      {err ? (
        <div style={{ marginTop: 12, background: `${T.warn}18`, border: `1px solid ${T.warn}44`, borderRadius: 12, padding: 12, color: T.warn, fontFamily: "DM Sans", fontSize: 12 }}>{err}</div>
      ) : null}
      {saved ? (
        <div style={{ marginTop: 12, background: `${T.coachGreen}18`, border: `1px solid ${T.coachGreen}44`, borderRadius: 12, padding: 12, color: T.coachGreen, fontFamily: "DM Sans", fontSize: 12 }}>✓ Saved</div>
      ) : null}

      <div style={{ marginTop: 14, overflowX: "auto" }}>
        <table style={{ width: "100%", borderCollapse: "separate", borderSpacing: 0 }}>
          <thead>
            <tr>
              <th style={thStyle()}>DAY</th>
              <th style={thStyle()}>CAL</th>
              <th style={thStyle()}>P</th>
              <th style={thStyle()}>C</th>
              <th style={thStyle()}>F</th>
            </tr>
          </thead>
          <tbody>
            {DAYS.map((d) => (
              <tr key={d}>
                <td style={tdStyle()}>{d}</td>
                <td style={tdStyle()}><input value={plan[d]?.calories ?? 0} onChange={(e) => setCell(d, "calories", e.target.value)} style={cellInput()} /></td>
                <td style={tdStyle()}><input value={plan[d]?.protein ?? 0} onChange={(e) => setCell(d, "protein", e.target.value)} style={cellInput()} /></td>
                <td style={tdStyle()}><input value={plan[d]?.carbs ?? 0} onChange={(e) => setCell(d, "carbs", e.target.value)} style={cellInput()} /></td>
                <td style={tdStyle()}><input value={plan[d]?.fat ?? 0} onChange={(e) => setCell(d, "fat", e.target.value)} style={cellInput()} /></td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}
/* ─────────────────────────────────────────────────────────────────────────────
   Athlete Mood Viewer — shows mood history for coach
────────────────────────────────────────────────────────────────────────────── */
/* ─────────────────────────────────────────────────────────────────────────────
   SVG Line Chart — reusable for mood & weight graphs
────────────────────────────────────────────────────────────────────────────── */
function TimeSeriesChart({ data, color, yLabel, yUnit, width = 560, height = 200, yMin: yMinProp, yMax: yMaxProp, formatY, emptyLabel }) {
  // data: [{ date: 'YYYY-MM-DD', value: number }] sorted by date ascending
  if (!data || data.length === 0) return <div style={{ color: T.muted, fontSize: 12 }}>{emptyLabel || "No data yet."}</div>;

  const pad = { top: 20, right: 16, bottom: 36, left: 44 };
  const w = width - pad.left - pad.right;
  const h = height - pad.top - pad.bottom;

  const vals = data.map(d => d.value);
  const yMin = yMinProp !== undefined ? yMinProp : Math.min(...vals) - (Math.max(...vals) - Math.min(...vals)) * 0.1;
  const yMax = yMaxProp !== undefined ? yMaxProp : Math.max(...vals) + (Math.max(...vals) - Math.min(...vals)) * 0.1;
  const yRange = yMax - yMin || 1;

  const xScale = (i) => pad.left + (data.length === 1 ? w / 2 : (i / (data.length - 1)) * w);
  const yScale = (v) => pad.top + h - ((v - yMin) / yRange) * h;

  const points = data.map((d, i) => `${xScale(i)},${yScale(d.value)}`);
  const line = points.join(" ");
  const areaPath = `M${xScale(0)},${yScale(data[0].value)} ` +
    data.map((d, i) => `L${xScale(i)},${yScale(d.value)}`).join(" ") +
    ` L${xScale(data.length - 1)},${pad.top + h} L${xScale(0)},${pad.top + h} Z`;

  // Y-axis labels (5 ticks)
  const yTicks = Array.from({ length: 5 }, (_, i) => yMin + (yRange * i) / 4);
  // X-axis labels (show ~6 dates)
  const step = Math.max(1, Math.floor(data.length / 6));
  const xLabels = data.filter((_, i) => i % step === 0 || i === data.length - 1);

  const dispY = formatY || ((v) => `${v}${yUnit || ""}`);

  return (
    <svg viewBox={`0 0 ${width} ${height}`} style={{ width: "100%", height: "auto", overflow: "visible" }}>
      {/* Grid lines */}
      {yTicks.map((t, i) => (
        <line key={i} x1={pad.left} x2={width - pad.right} y1={yScale(t)} y2={yScale(t)} stroke={T.border} strokeWidth={0.5} />
      ))}
      {/* Area fill */}
      <path d={areaPath} fill={`${color}15`} />
      {/* Line */}
      <polyline points={line} fill="none" stroke={color} strokeWidth={2} strokeLinejoin="round" strokeLinecap="round" />
      {/* Dots */}
      {data.map((d, i) => (
        <circle key={i} cx={xScale(i)} cy={yScale(d.value)} r={data.length > 60 ? 1.5 : 3} fill={color} stroke={T.card} strokeWidth={1} />
      ))}
      {/* Y-axis labels */}
      {yTicks.map((t, i) => (
        <text key={i} x={pad.left - 6} y={yScale(t) + 3} textAnchor="end" fill={T.muted} fontSize={9} fontFamily="JetBrains Mono, ui-monospace">
          {dispY(Math.round(t * 10) / 10)}
        </text>
      ))}
      {/* X-axis labels */}
      {xLabels.map((d) => {
        const idx = data.indexOf(d);
        const short = d.date.slice(5); // MM-DD
        return (
          <text key={d.date} x={xScale(idx)} y={height - 6} textAnchor="middle" fill={T.muted} fontSize={8} fontFamily="JetBrains Mono, ui-monospace">
            {short}
          </text>
        );
      })}
      {/* Axis label */}
      <text x={8} y={pad.top - 6} fill={T.muted} fontSize={9} fontFamily="DM Sans">{yLabel || ""}</text>
    </svg>
  );
}

/* ─────────────────────────────────────────────────────────────────────────────
   Athlete Mood Graph — SVG time-series over extended period
────────────────────────────────────────────────────────────────────────────── */
function AthleteMoodViewer({ athleteId, token }) {
  const [moods, setMoods] = useState([]);
  const [loading, setLoading] = useState(true);
  const [range, setRange] = useState(30);

  const load = async () => {
    if (!athleteId || !token) return;
    try {
      const rows = await apiFetch(`/moods/${athleteId}`, token);
      setMoods(Array.isArray(rows) ? rows : []);
    } catch { setMoods([]); }
    setLoading(false);
  };

  useEffect(() => { setLoading(true); load(); }, [athleteId, token]);

  // Filter by range, sort ascending by date
  const filtered = moods
    .filter(m => {
      const d = new Date(m.date);
      const cutoff = new Date(); cutoff.setDate(cutoff.getDate() - range);
      return d >= cutoff;
    })
    .sort((a, b) => a.date.localeCompare(b.date));

  const chartData = filtered.map(m => ({ date: m.date, value: Number(m.mood_id || 0) }));
  const avgScore = chartData.length > 0 ? (chartData.reduce((a, d) => a + d.value, 0) / chartData.length).toFixed(1) : "—";
  const latestMood = filtered[filtered.length - 1];

  const rangeOptions = [{ v: 7, l: "7D" }, { v: 14, l: "14D" }, { v: 30, l: "30D" }, { v: 90, l: "90D" }];

  return (
    <div style={{ background: T.card, border: `1px solid ${T.border}`, borderRadius: 16, padding: 18 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 14 }}>
        <div>
          <div style={{ fontFamily: "Bebas Neue, system-ui", fontSize: 18, letterSpacing: 2, color: T.text }}>MOOD TRACKING</div>
          <div style={{ fontFamily: "DM Sans", fontSize: 11, color: T.muted, marginTop: 2 }}>
            Avg: <span style={{ color: Number(avgScore) >= 4 ? T.coachGreen : Number(avgScore) >= 3 ? T.accent : T.danger, fontWeight: 700 }}>{avgScore}/5</span>
            {latestMood && <> · Latest: <span style={{ fontSize: 14 }}>{latestMood.emoji || "😶"}</span> {latestMood.label}</>}
            {latestMood?.note && <> — <span style={{ fontStyle: "italic" }}>"{latestMood.note}"</span></>}
          </div>
        </div>
        <div style={{ display: "flex", gap: 4 }}>
          {rangeOptions.map(r => (
            <button key={r.v} onClick={() => setRange(r.v)} style={{
              background: range === r.v ? `${T.accent}22` : "none",
              border: `1px solid ${range === r.v ? T.accent + "55" : T.border}`,
              borderRadius: 6, padding: "4px 10px", color: range === r.v ? T.accent : T.muted,
              fontFamily: "JetBrains Mono, ui-monospace", fontSize: 10, cursor: "pointer",
            }} type="button">{r.l}</button>
          ))}
        </div>
      </div>
      {loading ? <div style={{ color: T.muted, fontSize: 12 }}>Loading…</div> : (
        <TimeSeriesChart
          data={chartData}
          color="#f59e0b"
          yLabel="Mood Score"
          yUnit=""
          yMin={0.5}
          yMax={5.5}
          formatY={(v) => {
            const labels = { 1: "😞", 2: "😔", 3: "😐", 4: "🙂", 5: "😄" };
            return labels[Math.round(v)] || `${Math.round(v)}`;
          }}
          emptyLabel="No mood entries logged yet."
        />
      )}
    </div>
  );
}

/* ─────────────────────────────────────────────────────────────────────────────
   Athlete Weight Graph — SVG time-series over extended period
────────────────────────────────────────────────────────────────────────────── */
function AthleteWeightViewer({ athleteId, token }) {
  const [weights, setWeights] = useState([]);
  const [loading, setLoading] = useState(true);
  const [range, setRange] = useState(30);

  const load = async () => {
    if (!athleteId || !token) return;
    try {
      const rows = await apiFetch(`/weights/${athleteId}`, token);
      setWeights(Array.isArray(rows) ? rows : []);
    } catch { setWeights([]); }
    setLoading(false);
  };

  useEffect(() => { setLoading(true); load(); }, [athleteId, token]);

  const filtered = weights
    .filter(w => {
      const d = new Date(w.date);
      const cutoff = new Date(); cutoff.setDate(cutoff.getDate() - range);
      return d >= cutoff;
    })
    .sort((a, b) => a.date.localeCompare(b.date));

  const chartData = filtered.map(w => ({ date: w.date, value: Number(w.kg) }));
  const latest = chartData[chartData.length - 1]?.value;
  const oldest = chartData[0]?.value;
  const change = (latest && oldest) ? (latest - oldest).toFixed(1) : null;

  const rangeOptions = [{ v: 7, l: "7D" }, { v: 14, l: "14D" }, { v: 30, l: "30D" }, { v: 90, l: "90D" }, { v: 365, l: "1Y" }];

  return (
    <div style={{ background: T.card, border: `1px solid ${T.border}`, borderRadius: 16, padding: 18 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 14 }}>
        <div>
          <div style={{ fontFamily: "Bebas Neue, system-ui", fontSize: 18, letterSpacing: 2, color: T.text }}>WEIGHT TRACKING</div>
          <div style={{ fontFamily: "DM Sans", fontSize: 11, color: T.muted, marginTop: 2 }}>
            {latest ? <>Current: <span style={{ color: T.accent, fontWeight: 700 }}>{latest.toFixed(1)} kg</span></> : "No data"}
            {change !== null && <> · Change: <span style={{ color: Number(change) > 0 ? T.danger : Number(change) < 0 ? T.coachGreen : T.muted, fontWeight: 700 }}>{Number(change) >= 0 ? "+" : ""}{change} kg</span></>}
            {chartData.length > 0 && <> · {chartData.length} entries</>}
          </div>
        </div>
        <div style={{ display: "flex", gap: 4 }}>
          {rangeOptions.map(r => (
            <button key={r.v} onClick={() => setRange(r.v)} style={{
              background: range === r.v ? `${T.accent}22` : "none",
              border: `1px solid ${range === r.v ? T.accent + "55" : T.border}`,
              borderRadius: 6, padding: "4px 10px", color: range === r.v ? T.accent : T.muted,
              fontFamily: "JetBrains Mono, ui-monospace", fontSize: 10, cursor: "pointer",
            }} type="button">{r.l}</button>
          ))}
        </div>
      </div>
      {loading ? <div style={{ color: T.muted, fontSize: 12 }}>Loading…</div> : (
        <TimeSeriesChart
          data={chartData}
          color={T.accent}
          yLabel="Weight (kg)"
          yUnit=" kg"
          emptyLabel="No weight entries logged yet."
        />
      )}
    </div>
  );
}

/* ─────────────────────────────────────────────────────────────────────────────
   Athlete Food Log — auto-refreshes every 30s, shows daily cal bar chart + items
────────────────────────────────────────────────────────────────────────────── */
function AthleteFoodLogViewer({ athleteId, token, macroTarget }) {
  const [foodLogs, setFoodLogs] = useState([]);
  const [dailyTotals, setDailyTotals] = useState([]);
  const [loading, setLoading] = useState(true);
  const [range, setRange] = useState(7);
  const [expandedDay, setExpandedDay] = useState(null);

  const load = async () => {
    if (!athleteId || !token) return;
    try {
      const today = new Date();
      const start = new Date(today); start.setDate(today.getDate() - range);
      const fmt = (d) => `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
      const [logs, totals] = await Promise.all([
        apiFetch(`/food-logs/${athleteId}?start=${fmt(start)}&end=${fmt(today)}`, token),
        apiFetch(`/daily-totals/${athleteId}?start=${fmt(start)}&end=${fmt(today)}`, token),
      ]);
      setFoodLogs(Array.isArray(logs) ? logs : []);
      setDailyTotals(Array.isArray(totals) ? totals : []);
    } catch { setFoodLogs([]); setDailyTotals([]); }
    setLoading(false);
  };

  useEffect(() => { setLoading(true); load(); }, [athleteId, token, range]);

  // Auto-refresh every 30s
  useEffect(() => {
    if (!athleteId || !token) return;
    const interval = setInterval(load, 30 * 1000);
    return () => clearInterval(interval);
  }, [athleteId, token, range]);

  // Merge daily totals for chart
  const calTarget = macroTarget?.calories || 2000;
  const sorted = [...dailyTotals].sort((a, b) => a.date.localeCompare(b.date));
  const barMax = Math.max(calTarget, ...sorted.map(d => Number(d.calories || 0))) * 1.1;

  const rangeOptions = [{ v: 7, l: "7D" }, { v: 14, l: "14D" }, { v: 30, l: "30D" }];

  // Map food logs by date for expansion
  const foodsByDate = {};
  foodLogs.forEach(dl => { foodsByDate[dl.date] = dl.foods || []; });

  return (
    <div style={{ background: T.card, border: `1px solid ${T.border}`, borderRadius: 16, padding: 18 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 14 }}>
        <div>
          <div style={{ fontFamily: "Bebas Neue, system-ui", fontSize: 18, letterSpacing: 2, color: T.text }}>FOOD LOG</div>
          <div style={{ fontFamily: "DM Sans", fontSize: 11, color: T.muted, marginTop: 2 }}>
            Auto-refreshes every 30s · Click a day to expand items
          </div>
        </div>
        <div style={{ display: "flex", gap: 4, alignItems: "center" }}>
          <div style={{ width: 6, height: 6, borderRadius: "50%", background: T.coachGreen, animation: "pulse 2s infinite" }} />
          <span style={{ fontFamily: "DM Sans", fontSize: 10, color: T.coachGreen, marginRight: 8 }}>LIVE</span>
          {rangeOptions.map(r => (
            <button key={r.v} onClick={() => setRange(r.v)} style={{
              background: range === r.v ? `${T.accent}22` : "none",
              border: `1px solid ${range === r.v ? T.accent + "55" : T.border}`,
              borderRadius: 6, padding: "4px 10px", color: range === r.v ? T.accent : T.muted,
              fontFamily: "JetBrains Mono, ui-monospace", fontSize: 10, cursor: "pointer",
            }} type="button">{r.l}</button>
          ))}
        </div>
      </div>

      {loading ? <div style={{ color: T.muted, fontSize: 12 }}>Loading…</div> : sorted.length === 0 ? (
        <div style={{ color: T.muted, fontSize: 12 }}>No food logged in this period.</div>
      ) : (
        <>
          {/* Daily calorie bar chart */}
          <div style={{ marginBottom: 16 }}>
            <div style={{ display: "flex", alignItems: "flex-end", gap: 2, height: 100 }}>
              {sorted.map((d) => {
                const cal = Number(d.calories || 0);
                const pct = (cal / barMax) * 100;
                const over = cal > calTarget;
                const targetPct = (calTarget / barMax) * 100;
                const isExpanded = expandedDay === d.date;
                return (
                  <div key={d.date} style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", cursor: "pointer" }}
                    onClick={() => setExpandedDay(isExpanded ? null : d.date)}>
                    <div style={{ fontSize: 8, fontFamily: "JetBrains Mono, ui-monospace", color: T.muted, marginBottom: 2 }}>
                      {cal > 0 ? cal : ""}
                    </div>
                    <div style={{ width: "100%", position: "relative", height: 70 }}>
                      {/* Target line */}
                      <div style={{ position: "absolute", bottom: `${targetPct * 0.7}%`, left: 0, right: 0, height: 1, background: `${T.coachGreen}66`, zIndex: 2 }} />
                      {/* Bar */}
                      <div style={{
                        position: "absolute", bottom: 0, left: "10%", right: "10%",
                        height: `${Math.max(pct * 0.7, 2)}%`,
                        background: over ? `${T.danger}cc` : isExpanded ? T.accent : `${T.accent}88`,
                        borderRadius: "3px 3px 0 0",
                        transition: "all .2s",
                      }} />
                    </div>
                    <div style={{ fontSize: 7, fontFamily: "JetBrains Mono, ui-monospace", color: isExpanded ? T.accent : T.muted, marginTop: 2 }}>
                      {d.date.slice(5)}
                    </div>
                  </div>
                );
              })}
            </div>
            <div style={{ display: "flex", gap: 14, marginTop: 6 }}>
              <span style={{ fontSize: 9, color: T.muted, fontFamily: "DM Sans" }}>
                <span style={{ display: "inline-block", width: 10, height: 2, background: T.coachGreen, marginRight: 4, verticalAlign: "middle" }} />
                Target: {calTarget} cal
              </span>
            </div>
          </div>

          {/* Expanded food items for selected day */}
          {expandedDay && (
            <div style={{ background: T.surface, border: `1px solid ${T.border}`, borderRadius: 12, padding: 14, marginBottom: 12, animation: "fadeUp .15s ease" }}>
              <div style={{ fontFamily: "Bebas Neue, system-ui", fontSize: 14, letterSpacing: 1.5, color: T.accent, marginBottom: 8 }}>{expandedDay}</div>
              {(foodsByDate[expandedDay] || []).length === 0 ? (
                <div style={{ fontSize: 11, color: T.muted }}>No individual food items recorded for this day.</div>
              ) : (
                <>
                  {(() => {
                    const foods = foodsByDate[expandedDay];
                    const totP = foods.reduce((s, f) => s + Number(f.protein_g || f.protein || 0), 0);
                    const totC = foods.reduce((s, f) => s + Number(f.carbs_g || f.carbs || 0), 0);
                    const totF = foods.reduce((s, f) => s + Number(f.fat_g || f.fat || 0), 0);
                    return (
                      <div style={{ fontSize: 10, color: T.muted, marginBottom: 8, fontFamily: "JetBrains Mono, ui-monospace" }}>
                        P: {Math.round(totP)}g · C: {Math.round(totC)}g · F: {Math.round(totF)}g
                      </div>
                    );
                  })()}
                  {(foodsByDate[expandedDay]).map((f, j) => (
                    <div key={j} style={{ display: "flex", justifyContent: "space-between", padding: "4px 0", borderBottom: `1px solid ${T.border}20`, fontSize: 11 }}>
                      <span style={{ color: T.text }}>{f.name} {f.meal ? <span style={{ color: T.muted, fontSize: 9 }}>({f.meal})</span> : ""}</span>
                      <span style={{ color: T.muted, fontFamily: "JetBrains Mono, ui-monospace", fontSize: 10 }}>
                        {f.calories || 0} · {Math.round(Number(f.protein_g || f.protein || 0))}p · {Math.round(Number(f.carbs_g || f.carbs || 0))}c · {Math.round(Number(f.fat_g || f.fat || 0))}f
                      </span>
                    </div>
                  ))}
                </>
              )}
            </div>
          )}
        </>
      )}
    </div>
  );
}

/* ─────────────────────────────────────────────────────────────────────────────
   Athlete Calendar Manager — view + add events for athlete
────────────────────────────────────────────────────────────────────────────── */
function AthleteCalendarManager({ athleteId, token }) {
  const [events, setEvents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [form, setForm] = useState({ date: "", title: "", notes: "" });
  const [saving, setSaving] = useState(false);

  const loadEvents = async () => {
    try {
      const rows = await apiFetch(`/calendar-events/${athleteId}`, token);
      setEvents(Array.isArray(rows) ? rows : []);
    } catch { setEvents([]); }
  };

  useEffect(() => {
    if (!athleteId || !token) return;
    (async () => {
      setLoading(true);
      await loadEvents();
      setLoading(false);
    })();
  }, [athleteId, token]);

  const addEvent = async () => {
    if (!form.date || !form.title.trim()) return;
    setSaving(true);
    try {
      await apiFetch(`/calendar-events/${athleteId}`, token, {
        method: "POST",
        body: JSON.stringify({ date: form.date, title: form.title, startISO: form.date, endISO: form.date, notes: form.notes }),
      });
      setForm({ date: "", title: "", notes: "" });
      await loadEvents();
    } catch (e) { alert(e.message); }
    setSaving(false);
  };

  const deleteEvent = async (id) => {
    try {
      await apiFetch(`/calendar-events/${athleteId}/${id}`, token, { method: "DELETE" });
      await loadEvents();
    } catch (e) { alert(e.message); }
  };

  return (
    <div style={{ background: T.card, border: `1px solid ${T.border}`, borderRadius: 16, padding: 18 }}>
      <div style={{ fontFamily: "Bebas Neue, system-ui", fontSize: 18, letterSpacing: 2, color: T.text, marginBottom: 14 }}>CALENDAR EVENTS</div>

      {/* Add event form */}
      <div style={{ display: "grid", gridTemplateColumns: "1fr 2fr 2fr auto", gap: 8, marginBottom: 14, alignItems: "end" }}>
        <div>
          <label style={labelStyle}>Date</label>
          <input type="date" value={form.date} onChange={(e) => setForm(p => ({...p, date: e.target.value}))} style={inputStyle} />
        </div>
        <div>
          <label style={labelStyle}>Title</label>
          <input value={form.title} onChange={(e) => setForm(p => ({...p, title: e.target.value}))} placeholder="e.g. Check-in call" style={inputStyle} />
        </div>
        <div>
          <label style={labelStyle}>Notes</label>
          <input value={form.notes} onChange={(e) => setForm(p => ({...p, notes: e.target.value}))} placeholder="Optional notes" style={inputStyle} />
        </div>
        <button onClick={addEvent} disabled={saving || !form.date || !form.title.trim()} style={{
          background: form.date && form.title.trim() ? T.accent : T.border,
          color: form.date && form.title.trim() ? T.bg : T.muted,
          border: "none", borderRadius: 10, padding: "11px 16px",
          fontFamily: "Bebas Neue, system-ui", fontSize: 13, letterSpacing: 1.5,
          cursor: form.date && form.title.trim() && !saving ? "pointer" : "default",
        }} type="button">{saving ? "…" : "ADD"}</button>
      </div>

      {loading ? <div style={{ color: T.muted, fontSize: 12 }}>Loading…</div> : events.length === 0 ? (
        <div style={{ color: T.muted, fontSize: 12 }}>No calendar events yet. Add one above.</div>
      ) : (
        <div style={{ maxHeight: 300, overflowY: "auto" }}>
          {events.map((ev) => (
            <div key={ev.id} style={{ display: "flex", alignItems: "center", gap: 10, padding: "8px 0", borderBottom: `1px solid ${T.border}20` }}>
              <span style={{ fontFamily: "JetBrains Mono, ui-monospace", fontSize: 10, color: T.accent, whiteSpace: "nowrap" }}>{ev.date}</span>
              <div style={{ flex: 1 }}>
                <div style={{ fontSize: 12, color: T.text, fontWeight: 600 }}>{ev.title}</div>
                {ev.notes && <div style={{ fontSize: 11, color: T.muted, marginTop: 1 }}>{ev.notes}</div>}
              </div>
              <button onClick={() => deleteEvent(ev.id)} style={{ background: "none", border: `1px solid ${T.danger}44`, borderRadius: 6, padding: "4px 8px", color: T.danger, fontSize: 10, cursor: "pointer" }} type="button">✕</button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

/* ─────────────────────────────────────────────────────────────────────────────
   Weekly Adherence Dashboard — shows each day's targets vs actuals as % bars
────────────────────────────────────────────────────────────────────────────── */
function WeeklyAdherenceView({ athleteId, token }) {
  const [targets, setTargets] = useState({}); // { MON: {cal,p,c,f}, ... }
  const [actuals, setActuals] = useState({}); // { '2025-03-10': {cal,p,c,f}, ... }
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!athleteId || !token) return;
    let ignore = false;
    (async () => {
      setLoading(true);
      try {
        // Get macro plans (targets per day of week)
        const plans = await apiFetch(`/macro-plans/${athleteId}`, token);
        const byDay = {};
        (Array.isArray(plans) ? plans : []).forEach(r => {
          byDay[r.day_of_week] = {
            calories: Number(r.calories || 0),
            protein: Number(r.protein_g || 0),
            carbs: Number(r.carbs_g || 0),
            fat: Number(r.fat_g || 0),
          };
        });
        if (!ignore) setTargets(byDay);

        // Get daily totals for last 7 days
        const today = new Date();
        const start = new Date(today); start.setDate(today.getDate() - 6);
        const fmt = (d) => `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
        const totals = await apiFetch(`/daily-totals/${athleteId}?start=${fmt(start)}&end=${fmt(today)}`, token);
        const byDate = {};
        (Array.isArray(totals) ? totals : []).forEach(r => {
          byDate[r.date] = {
            calories: Number(r.calories || 0),
            protein: Number(r.protein_g || 0),
            carbs: Number(r.carbs_g || 0),
            fat: Number(r.fat_g || 0),
          };
        });
        if (!ignore) setActuals(byDate);
      } catch {}
      if (!ignore) setLoading(false);
    })();
    return () => { ignore = true; };
  }, [athleteId, token]);

  // Auto-refresh every 30s
  useEffect(() => {
    if (!athleteId || !token) return;
    const refresh = async () => {
      try {
        const today = new Date();
        const start = new Date(today); start.setDate(today.getDate() - 6);
        const fmt = (d) => `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
        const totals = await apiFetch(`/daily-totals/${athleteId}?start=${fmt(start)}&end=${fmt(today)}`, token);
        const byDate = {};
        (Array.isArray(totals) ? totals : []).forEach(r => {
          byDate[r.date] = {
            calories: Number(r.calories || 0),
            protein: Number(r.protein_g || 0),
            carbs: Number(r.carbs_g || 0),
            fat: Number(r.fat_g || 0),
          };
        });
        setActuals(byDate);
      } catch {}
    };
    const interval = setInterval(refresh, 30 * 1000);
    return () => clearInterval(interval);
  }, [athleteId, token]);

  // Build last 7 days with day key + date
  const days = [];
  for (let i = 6; i >= 0; i--) {
    const d = new Date(); d.setDate(d.getDate() - i);
    const dow = d.getDay();
    const dayKey = DAYS[dow === 0 ? 6 : dow - 1];
    const dateStr = `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
    days.push({ dayKey, dateStr, isToday: i === 0 });
  }

  const pctColor = (pct) => {
    if (pct === null) return T.muted;
    if (pct >= 90 && pct <= 110) return T.coachGreen;
    if (pct >= 75 && pct <= 125) return T.warn;
    return T.danger;
  };

  const macros = [
    { key: "calories", label: "CAL", color: T.accent },
    { key: "protein", label: "P", color: T.protein },
    { key: "carbs", label: "C", color: T.carbs },
    { key: "fat", label: "F", color: T.fat },
  ];

  // Overall adherence for the week
  let adheredDays = 0;
  let totalTracked = 0;
  days.forEach(({ dayKey, dateStr }) => {
    const target = targets[dayKey];
    const actual = actuals[dateStr];
    if (target && actual && target.calories > 0 && actual.calories > 0) {
      totalTracked++;
      const calPct = (actual.calories / target.calories) * 100;
      if (calPct >= 80 && calPct <= 120) adheredDays++;
    }
  });
  const weekPct = totalTracked > 0 ? Math.round((adheredDays / totalTracked) * 100) : null;

  if (loading) return <div style={{ color: T.muted, fontSize: 12, padding: 18 }}>Loading weekly overview…</div>;

  return (
    <div style={{ background: T.card, border: `1px solid ${T.border}`, borderRadius: 16, padding: 18 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
        <div>
          <div style={{ fontFamily: "Bebas Neue, system-ui", fontSize: 18, letterSpacing: 2, color: T.text }}>WEEKLY ADHERENCE</div>
          <div style={{ fontFamily: "DM Sans", fontSize: 11, color: T.muted, marginTop: 2 }}>
            Target vs actual for each day · Auto-refreshes every 30s
          </div>
        </div>
        <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
          <div style={{ width: 6, height: 6, borderRadius: "50%", background: T.coachGreen, animation: "pulse 2s infinite" }} />
          <span style={{ fontFamily: "DM Sans", fontSize: 10, color: T.coachGreen }}>LIVE</span>
          {weekPct !== null && (
            <span style={{
              fontFamily: "Bebas Neue, system-ui", fontSize: 22,
              color: weekPct >= 80 ? T.coachGreen : weekPct >= 60 ? T.warn : T.danger,
            }}>{weekPct}%</span>
          )}
        </div>
      </div>

      {/* Legend */}
      <div style={{ display: "flex", gap: 16, marginBottom: 14, fontSize: 10, fontFamily: "DM Sans" }}>
        <span><span style={{ display: "inline-block", width: 8, height: 8, borderRadius: 2, background: T.coachGreen, marginRight: 4, verticalAlign: "middle" }} />90–110%</span>
        <span><span style={{ display: "inline-block", width: 8, height: 8, borderRadius: 2, background: T.warn, marginRight: 4, verticalAlign: "middle" }} />75–125%</span>
        <span><span style={{ display: "inline-block", width: 8, height: 8, borderRadius: 2, background: T.danger, marginRight: 4, verticalAlign: "middle" }} />Outside</span>
        <span style={{ color: T.muted }}><span style={{ display: "inline-block", width: 8, height: 8, borderRadius: 2, background: T.border, marginRight: 4, verticalAlign: "middle" }} />No data</span>
      </div>

      {/* Day rows */}
      <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
        {days.map(({ dayKey, dateStr, isToday }) => {
          const target = targets[dayKey] || {};
          const actual = actuals[dateStr] || {};
          const hasData = actual.calories > 0;

          return (
            <div key={dateStr} style={{
              background: isToday ? `${T.accent}08` : "transparent",
              border: isToday ? `1px solid ${T.accent}22` : `1px solid transparent`,
              borderRadius: 10, padding: "10px 12px",
            }}>
              <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 6 }}>
                <span style={{
                  fontFamily: "Bebas Neue, system-ui", fontSize: 14, letterSpacing: 1.5,
                  color: isToday ? T.accent : T.text, minWidth: 36,
                }}>{dayKey}</span>
                <span style={{ fontFamily: "JetBrains Mono, ui-monospace", fontSize: 9, color: T.muted }}>{dateStr.slice(5)}</span>
                {isToday && <span style={{ fontSize: 9, color: T.accent, fontFamily: "DM Sans", fontWeight: 700 }}>TODAY</span>}
                {!hasData && <span style={{ fontSize: 9, color: T.muted, fontFamily: "DM Sans", fontStyle: "italic" }}>No food logged</span>}
              </div>

              {hasData && (
                <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 6 }}>
                  {macros.map(m => {
                    const tgt = target[m.key] || 0;
                    const act = actual[m.key] || 0;
                    const pct = tgt > 0 ? Math.round((act / tgt) * 100) : null;
                    const barPct = pct !== null ? Math.min(pct, 150) : 0;
                    const col = pctColor(pct);

                    return (
                      <div key={m.key}>
                        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 3 }}>
                          <span style={{ fontSize: 9, fontFamily: "DM Sans", color: T.muted, fontWeight: 600 }}>{m.label}</span>
                          <span style={{ fontSize: 10, fontFamily: "JetBrains Mono, ui-monospace", color: col, fontWeight: 700 }}>
                            {pct !== null ? `${pct}%` : "—"}
                          </span>
                        </div>
                        {/* Bar */}
                        <div style={{ height: 6, background: T.border, borderRadius: 3, overflow: "hidden", position: "relative" }}>
                          {/* Target marker at 100% */}
                          <div style={{ position: "absolute", left: `${Math.min(100 / 1.5, 100)}%`, top: 0, bottom: 0, width: 1, background: `${T.text}33`, zIndex: 2 }} />
                          <div style={{
                            height: "100%", borderRadius: 3,
                            width: `${Math.min(barPct / 1.5, 100)}%`,
                            background: col,
                            transition: "width .3s ease",
                          }} />
                        </div>
                        <div style={{ display: "flex", justifyContent: "space-between", marginTop: 2 }}>
                          <span style={{ fontSize: 8, fontFamily: "JetBrains Mono, ui-monospace", color: T.muted }}>
                            {Math.round(act)}{m.key === "calories" ? "" : "g"}
                          </span>
                          <span style={{ fontSize: 8, fontFamily: "JetBrains Mono, ui-monospace", color: T.muted }}>
                            /{Math.round(tgt)}{m.key === "calories" ? "" : "g"}
                          </span>
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}

              {!hasData && (
                <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 6 }}>
                  {macros.map(m => (
                    <div key={m.key}>
                      <div style={{ height: 6, background: T.border, borderRadius: 3 }} />
                      <div style={{ fontSize: 8, color: T.muted, marginTop: 2, fontFamily: "JetBrains Mono, ui-monospace", textAlign: "center" }}>—</div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

function AthleteDetail({ athlete, token, onBack, onDelete }) {
  const [tab, setTab] = useState("nutrition");
  const [editing, setEditing] = useState(false);
  const [deleting, setDeleting] = useState(false);
  const [confirmDelete, setConfirmDelete] = useState(false);
  const [initialGoals, setInitialGoals] = useState(() => ({
    calories: athlete.macroGoals?.calories ?? 2500,
    protein: athlete.macroGoals?.protein ?? 180,
    carbs: athlete.macroGoals?.carbs ?? 280,
    fat: athlete.macroGoals?.fat ?? 75,
  }));
  const [goals, setGoals] = useState(() => initialGoals);
  const [saved, setSaved] = useState(false);

  const handleSaveTargets = async () => {
    // Persist these targets by applying them to ALL days in the macro plan and saving to backend
    try {
      const payload = {
        plans: DAYS.map((d) => ({
          dayOfWeek: d,
          calories: goals.calories,
          protein_g: goals.protein,
          carbs_g: goals.carbs,
          fat_g: goals.fat,
        })),
      };
      await apiFetch(`/macro-plans/${athlete.id}`, token, {
        method: "PUT",
        body: JSON.stringify(payload),
      });
      setInitialGoals(goals);
      setEditing(false);
      setSaved(true);
      setTimeout(() => setSaved(false), 1800);
    } catch (e) {
      alert(e.message || "Could not save targets");
    }
  };

  const tabs = [
    { id: "nutrition", label: "NUTRITION" },
    { id: "macroplan", label: "MACRO PLAN" },
    { id: "data", label: "MOOD & WEIGHT" },
    { id: "foodlog", label: "FOOD LOG" },
    { id: "calendar", label: "CALENDAR" },
  ];

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 16, animation: "fadeUp .2s ease" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
        <button
          onClick={onBack}
          style={{
            background: T.card,
            border: `1px solid ${T.border}`,
            borderRadius: 8,
            padding: "6px 14px",
            color: T.muted,
            fontFamily: "DM Sans",
            fontSize: 12,
            cursor: "pointer",
          }}
          type="button"
        >
          ← Back
        </button>

        <Avatar initials={athlete.avatar} color={athlete.avatarColor} size={52} />

        <div style={{ flex: 1 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 2 }}>
            <span style={{ fontFamily: "Bebas Neue, system-ui", fontSize: 26, letterSpacing: 1.5, color: T.text }}>
              {athlete.name.toUpperCase()}
            </span>
            <Badge label={athlete.sport || "ATHLETE"} color={T.coachGreen} />
          </div>

          <div style={{ fontFamily: "JetBrains Mono, ui-monospace", fontSize: 11, color: T.muted }}>
            {athlete.email}
          </div>
        </div>

        {/* Delete athlete button */}
        {!confirmDelete ? (
          <button
            onClick={() => setConfirmDelete(true)}
            style={{
              background: "none",
              border: `1px solid ${T.danger}44`,
              borderRadius: 8,
              padding: "6px 14px",
              color: T.danger,
              fontFamily: "DM Sans",
              fontSize: 11,
              cursor: "pointer",
            }}
            type="button"
          >
            Delete Client
          </button>
        ) : (
          <div style={{ display: "flex", gap: 6, alignItems: "center" }}>
            <span style={{ fontSize: 11, color: T.danger, fontFamily: "DM Sans" }}>Are you sure?</span>
            <button
              onClick={async () => {
                setDeleting(true);
                try {
                  await apiFetch(`/athletes/${athlete.id}`, token, { method: "DELETE" });
                  onDelete?.(athlete.id);
                } catch (e) {
                  alert(e.message || "Could not delete athlete");
                  setDeleting(false);
                  setConfirmDelete(false);
                }
              }}
              disabled={deleting}
              style={{
                background: T.danger,
                border: "none",
                borderRadius: 6,
                padding: "5px 12px",
                color: "#fff",
                fontFamily: "Bebas Neue, system-ui",
                fontSize: 12,
                letterSpacing: 1,
                cursor: deleting ? "default" : "pointer",
              }}
              type="button"
            >
              {deleting ? "DELETING…" : "YES, DELETE"}
            </button>
            <button
              onClick={() => setConfirmDelete(false)}
              style={{
                background: "none",
                border: `1px solid ${T.border}`,
                borderRadius: 6,
                padding: "5px 10px",
                color: T.muted,
                fontFamily: "DM Sans",
                fontSize: 11,
                cursor: "pointer",
              }}
              type="button"
            >
              Cancel
            </button>
          </div>
        )}
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 12 }}>
        <StatCard label="CAL TARGET" value={goals.calories} color={T.accent} unit="kcal" />
        <StatCard label="PROTEIN" value={goals.protein} color={T.protein} unit="g" />
        <StatCard label="CARBS" value={goals.carbs} color={T.carbs} unit="g" />
        <StatCard label="FAT" value={goals.fat} color={T.fat} unit="g" />
      </div>

      <div style={{ display: "flex", borderBottom: `1px solid ${T.border}`, gap: 1, overflowX: "auto" }}>
        {tabs.map((t) => (
          <button
            key={t.id}
            onClick={() => setTab(t.id)}
            style={{
              padding: "10px 16px",
              background: "none",
              border: "none",
              cursor: "pointer",
              fontFamily: "Bebas Neue, system-ui",
              fontSize: 13,
              letterSpacing: 1.5,
              color: tab === t.id ? T.accent : T.muted,
              whiteSpace: "nowrap",
              borderBottom: tab === t.id ? `2px solid ${T.accent}` : "2px solid transparent",
              marginBottom: -1,
              transition: "all .2s",
            }}
            type="button"
          >
            {t.label}
          </button>
        ))}
      </div>

      {tab === "nutrition" && (
        <>
        <div style={{ background: T.card, border: `1px solid ${T.border}`, borderRadius: 18, padding: 22 }}>
          {saved && (
            <div
              style={{
                background: `${T.coachGreen}18`,
                border: `1px solid ${T.coachGreen}44`,
                borderRadius: 10,
                padding: "10px 14px",
                fontFamily: "DM Sans",
                fontSize: 12,
                color: T.coachGreen,
                marginBottom: 12,
              }}
            >
              ✓ Targets updated (local defaults for macro overview).
            </div>
          )}

          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 14 }}>
            <div>
              <div style={{ fontFamily: "Bebas Neue, system-ui", fontSize: 18, letterSpacing: 2, color: T.text }}>
                MACRO TARGETS (DEFAULTS)
              </div>
              <div style={{ fontFamily: "DM Sans", fontSize: 11, color: T.muted, marginTop: 4 }}>
                Used by “Populate all days” in the Macro Plan tab.
              </div>
            </div>

            <div style={{ display: "flex", gap: 8 }}>
              {editing ? (
                <>
                  <button
                    onClick={() => {
                      setGoals({
                        calories: athlete.macroGoals?.calories ?? 2500,
                        protein: athlete.macroGoals?.protein ?? 180,
                        carbs: athlete.macroGoals?.carbs ?? 280,
                        fat: athlete.macroGoals?.fat ?? 75,
                      });
                      setEditing(false);
                    }}
                    style={{
                      background: "none",
                      border: `1px solid ${T.border}`,
                      borderRadius: 10,
                      padding: "8px 12px",
                      color: T.muted,
                      fontFamily: "DM Sans",
                      fontSize: 12,
                      cursor: "pointer",
                    }}
                    type="button"
                  >
                    Cancel
                  </button>

                  <button
                    onClick={handleSaveTargets}
                    style={{
                      background: T.accent,
                      border: "none",
                      borderRadius: 10,
                      padding: "8px 14px",
                      color: T.bg,
                      fontFamily: "Bebas Neue, system-ui",
                      fontSize: 14,
                      letterSpacing: 1.5,
                      cursor: "pointer",
                    }}
                    type="button"
                  >
                    SAVE
                  </button>
                </>
              ) : (
                <button
                  onClick={() => setEditing(true)}
                  style={{
                    background: "none",
                    border: `1px solid ${T.accent}44`,
                    borderRadius: 10,
                    padding: "8px 14px",
                    color: T.accent,
                    fontFamily: "DM Sans",
                    fontSize: 12,
                    cursor: "pointer",
                  }}
                  type="button"
                >
                  ✏ Edit Targets
                </button>
              )}
            </div>
          </div>

          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
            {[
              { key: "calories", label: "Calories", unit: "kcal", color: T.accent },
              { key: "protein", label: "Protein", unit: "g", color: T.protein },
              { key: "carbs", label: "Carbs", unit: "g", color: T.carbs },
              { key: "fat", label: "Fat", unit: "g", color: T.fat },
            ].map((m) => (
              <div key={m.key}>
                <label style={labelStyle}>{m.label}</label>
                {editing ? (
                  <input
                    type="number"
                    value={goals[m.key]}
                    onChange={(e) => setGoals((g) => ({ ...g, [m.key]: clamp(Number(e.target.value), 0, 20000) }))}
                    style={{
                      ...inputStyle,
                      border: `1px solid ${m.color}44`,
                      color: m.color,
                      fontFamily: "JetBrains Mono, ui-monospace",
                      fontSize: 14,
                      fontWeight: 700,
                    }}
                  />
                ) : (
                  <div style={{ display: "flex", alignItems: "baseline", gap: 6 }}>
                    <span style={{ fontFamily: "Bebas Neue, system-ui", fontSize: 30, color: m.color }}>{goals[m.key]}</span>
                    <span style={{ fontFamily: "DM Sans", fontSize: 12, color: T.muted }}>{m.unit}</span>
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>

        {/* Weekly adherence dashboard */}
        <WeeklyAdherenceView athleteId={athlete.id} token={token} />
        </>
      )}

      {tab === "macroplan" && (
        <WeeklyMacroPlan athleteId={athlete.id} baseTargets={goals} token={token} onSaved={(p) => {
        const tot = DAYS.reduce((a, d) => ({
          calories: a.calories + Number(p[d].calories || 0),
          protein: a.protein + Number(p[d].protein || 0),
          carbs: a.carbs + Number(p[d].carbs || 0),
          fat: a.fat + Number(p[d].fat || 0),
        }), { calories: 0, protein: 0, carbs: 0, fat: 0 });
        const next = {
          calories: Math.round(tot.calories / 7),
          protein: Math.round(tot.protein / 7),
          carbs: Math.round(tot.carbs / 7),
          fat: Math.round(tot.fat / 7),
        };
        setInitialGoals(next);
        setGoals(next);
      }} />
      )}

      {tab === "data" && (
        <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
          <AthleteMoodViewer athleteId={athlete.id} token={token} />
          <AthleteWeightViewer athleteId={athlete.id} token={token} />
        </div>
      )}

      {tab === "foodlog" && (
        <AthleteFoodLogViewer athleteId={athlete.id} token={token} macroTarget={goals} />
      )}

      {tab === "calendar" && (
        <AthleteCalendarManager athleteId={athlete.id} token={token} />
      )}
    </div>
  );
}

